588: func (pl *DynamicResources) validateDeviceClass(logger klog.Logger, deviceClassName, requestName string) *fwk.Status {
589: 	if deviceClassName == "" {
590: 		return statusError(logger, fmt.Errorf("request %s: unsupported request type", requestName))
591: 	}
592: 
593: 	_, err := pl.draManager.DeviceClasses().Get(deviceClassName)
594: 	if err != nil {
